function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    const inDegree = new Array(n).fill(0);

    for (const [u, v, cost] of edges) {
        adj[u].push({ v, cost });
        inDegree[v]++;
    }

    const topo = [];
    const queue = [];

    for (let i = 0; i < n; i++) {
        if (inDegree[i] === 0) {
            queue.push(i);
        }
    }

    while (queue.length > 0) {
        const u = queue.shift();
        topo.push(u);
        for (const edge of adj[u]) {
            const v = edge.v;
            inDegree[v]--;
            if (inDegree[v] === 0) {
                queue.push(v);
            }
        }
    }

    let low = 0;
    let high = 0;

    for (const [u, v, cost] of edges) {
        high = Math.max(high, cost);
    }

    let answer = -1;

    function check(mid) {
        const minCost = new Array(n).fill(Infinity);
        minCost[0] = 0;

        for (const u of topo) {
            if (!online[u]) continue;
            for (const edge of adj[u]) {
                const v = edge.v;
                const cost = edge.cost;
                if (cost >= mid && online[v]) {
                    if (minCost[u] + cost < minCost[v]) {
                        minCost[v] = minCost[u] + cost;
                    }
                }
            }
        }

        return minCost[n - 1] <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}

