fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val adj = Array(n) { mutableListOf<Pair<Long, Long>>() }
    val inDegree = LongArray(n).apply { fill(0L) }

    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val cost = edge[2]
        adj[u].add(Pair(v.toLong(), cost))
        inDegree[v] += 1
    }

    val topo = mutableListOf<Int>()
    val queue = LinkedList<Int>()

    for (i in 0 until n) {
        if (inDegree[i] == 0L) {
            queue.add(i)
        }
    }

    while (queue.isNotEmpty()) {
        val u = queue.removeFirst()
        topo.add(u)
        for (edge in adj[u]) {
            val v = edge.first
            inDegree[v.toInt()] -= 1
            if (inDegree[v.toInt()] == 0L) {
                queue.add(v.toInt())
            }
        }
    }

    var maxEdge = 0L
    for (edge in edges) {
        maxEdge = maxOf(maxEdge, edge[2])
    }

    var low = 0L
    var high = maxEdge
    var answer = -1L

    fun check(mid: Long): Boolean {
        val minCost = LongArray(n).apply { fill(Long.MAX_VALUE) }
        minCost[0] = 0L

        for (u in topo) {
            if (!online[u]) continue
            for (edge in adj[u]) {
                val v = edge.first
                val cost = edge.second
                if (cost >= mid && online[v.toInt()]) {
                    if (minCost[u] + cost < minCost[v.toInt()]) {
                        minCost[v.toInt()] = minCost[u] + cost
                    }
                }
            }
        }

        return minCost[n - 1] <= k
    }

    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            answer = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return answer
}
